/// AES-128 encrypted PDF with correct user password decrypts (no error, not flagged encrypted).
#[test]
fn aes128_encrypted_with_password() {
    let blob = fixture("aes128_encrypted.pdf");
    let mut budget = Budget::with_passwords(Limits::default(), vec!["user123".to_string()]);
    let result = extract(Format::Pdf, &blob, &mut budget);
    // With the correct password, extraction should succeed without error
    // (blank pages have no streams, so entries may be empty)
    assert!(
        result.is_ok(),
        "AES-128 with password should not error: {result:?}"
    );
}

