/// Linearized PDF 1.4 (2 pages) extracts without errors.
#[test]
fn linearized_pdf() {
    let blob = fixture("linearized_2page.pdf");
    let mut budget = Budget::new(Limits::default());
    let entries = extract(Format::Pdf, &blob, &mut budget).unwrap();
    assert!(
        entries.iter().all(|e| !e.encrypted),
        "linearized PDF should not be encrypted"
    );
}
